@st.cache_resource
def load_model():
    return joblib.load("model.pkl")

model = load_model()

st.markdown("""
<div class="hero">
    <div class="hero-eyebrow">г. Рязань · Недвижимость</div>
    <h1>Оценка стоимости квартиры</h1>
    <p>Введите параметры — модель мгновенно рассчитает рыночную цену</p>
    <div class="gold-line"></div>
</div>
""", unsafe_allow_html=True)

st.markdown('<div class="sec-label">Расположение</div>', unsafe_allow_html=True)
col1, col2 = st.columns(2)
with col1:
    district = st.selectbox("Административный район", list(DISTRICTS.keys()))
with col2:
    neighbourhood = st.selectbox("Микрорайон", DISTRICTS[district])
dist_km = NBHD_DIST[neighbourhood]
st.markdown(
    f'<div class="info-pill">Удалённость от центра: <strong>{dist_km} км</strong></div>',
    unsafe_allow_html=True,
)

st.markdown('<div class="sec-label">Площадь и планировка</div>', unsafe_allow_html=True)
col3, col4 = st.columns(2)
with col3:
    area = st.number_input("Общая площадь, м²", min_value=18.0, max_value=230.0,
                            value=55.0, step=0.5, format="%.1f")
with col4:
    rooms = st.number_input("Количество комнат", min_value=1, max_value=6, value=2)

st.markdown('<div class="sec-label">Характеристики дома</div>', unsafe_allow_html=True)
col5, col6, col7 = st.columns(3)
with col5:
    house_type = st.selectbox("Тип дома", HOUSE_TYPES)
with col6:
    year_built = st.number_input("Год постройки", min_value=1960, max_value=2026,
                                  value=2010, step=1)
with col7:
    total_floors = st.number_input("Этажей в доме", min_value=2, max_value=30, value=16)

col8, _, __ = st.columns(3)
with col8:
    floor = st.number_input("Этаж квартиры", min_value=1,
                             max_value=int(total_floors),
                             value=min(7, int(total_floors)))

st.markdown('<div class="sec-label">Дополнительно</div>', unsafe_allow_html=True)
col11, col12, col13 = st.columns(3)
with col11:
    renovation = st.selectbox("Состояние ремонта", RENOV_TYPES, index=2)
with col12:
    has_parking = st.checkbox("Парковка", value=False)
with col13:
    has_balcony = st.checkbox("Балкон / лоджия", value=True)

st.markdown("<div style='height:16px'></div>", unsafe_allow_html=True)
calc = st.button("Рассчитать стоимость")

if calc:
    inp = pd.DataFrame([{
        "административный_район":   district,
        "микрорайон":               neighbourhood,
        "площадь_м2":               area,
        "комнат":                   int(rooms),
        "этаж":                     int(floor),
        "этажей_в_доме":            int(total_floors),
        "тип_дома":                 house_type,
        "год_постройки":            int(year_built),
        "удаленность_от_центра_км": dist_km,
        "парковка":                 int(has_parking),
        "балкон":                   int(has_balcony),
        "ремонт":                   renovation,
    }])
    inp["возраст_дома"]       = 2025 - inp["год_постройки"]
    inp["соотношение_этажей"] = inp["этаж"] / inp["этажей_в_доме"]
    inp["площадь_на_комнату"] = inp["площадь_м2"] / inp["комнат"]

    price    = model.predict(inp)[0]
    price_m2 = price / area
    mln      = price / 1_000_000

    extras_list = []
    if has_parking: extras_list.append("Парковка")
    if has_balcony: extras_list.append("Балкон")
    extras = " · ".join(extras_list) if extras_list else "—"

    st.markdown(f"""
    <div class="result-card">
      <div class="res-eyebrow">ОЦЕНОЧНАЯ СТОИМОСТЬ</div>
      <div class="res-price">{mln:.2f}<span class="res-unit">млн ₽</span></div>
      <div class="res-raw">{price:,.0f} ₽ &nbsp;·&nbsp; {price_m2:,.0f} ₽/м²</div>
      <div class="res-chips">
        <span class="res-chip"><b>{area:.0f} м²</b></span>
        <span class="res-chip"><b>{house_type}</b></span>
        <span class="res-chip"><b>{district}</b>, {neighbourhood}</span>
        <span class="res-chip"><b>{renovation}</b></span>
        <span class="res-chip">{extras}</span>
      </div>
    </div>
    """, unsafe_allow_html=True)
